def sanitize_headers(headers):
    """Remove sensitive information from headers before logging"""
    sensitive_headers = ['authorization', 'cookie', 'x-api-key', 'x-auth-token']
    sanitized = dict(headers)
    for header in sensitive_headers:
        if header in sanitized:
            sanitized[header] = '[REDACTED]'
    return sanitized


def sanitize_data(data):
    """Remove sensitive information from request/response data before logging"""
    if not isinstance(data, dict):
        return data
    
    sensitive_fields = ['password', 'token', 'secret', 'api_key', 'auth_token', 
                       'credit_card', 'ssn', 'access_token', 'refresh_token']
    sanitized = data.copy()
    
    for key in list(sanitized.keys()):
        if any(sensitive in key.lower() for sensitive in sensitive_fields):
            sanitized[key] = '[REDACTED]'
        elif isinstance(sanitized[key], dict):
            sanitized[key] = sanitize_data(sanitized[key])
    
    return sanitized


@app.before_request
def log_request_info():
    """Log incoming request details with sanitized sensitive data"""
