def require_auth(f):
    """Authentication decorator"""
    @wraps(f)
    def decorated_function(*args, **kwargs):
        auth_header = request.headers.get('Authorization')
        
        if not auth_header or not auth_header.startswith('Bearer '):
            app.logger.warning(
                f"Authentication failed - Missing or invalid authorization header - "
                f"Request ID: {getattr(g, 'request_id', 'unknown')}, "
                f"Path: {request.path}"
            )
            return jsonify({'error': 'Authentication required'}), 401
        
        token = auth_header.split(' ')[1]
        
        if token not in SESSIONS:
            app.logger.warning(
                f"Authentication failed - Invalid token - "
                f"Request ID: {getattr(g, 'request_id', 'unknown')}, "
                f"Path: {request.path}"
            )
            return jsonify({'error': 'Invalid or expired token'}), 401
        
        g.user = SESSIONS[token]
        app.logger.info(
            f"Authentication successful - User: {g.user['username']}, "
            f"Request ID: {getattr(g, 'request_id', 'unknown')}"
        )
        
        return f(*args, **kwargs)
    
    return decorated_function


@app.route('/api/login', methods=['POST'])
def login():
    """Login endpoint - NEVER log passwords in production"""
    if not request.is_json:
        app.logger.warning(f"Login failed - Invalid content type - Request ID: {g.request_id}")
        return jsonify({'error': 'Content-Type must be application/json'}), 400
    
    data = request.get_json()
    username = data.get('username')
    password = data.get('password')
    
    if not username or not password:
        app.logger.warning(
            f"Login failed - Missing credentials - "
            f"Username provided: {bool(username)}, "
            f"Request ID: {g.request_id}"
        )
        return jsonify({'error': 'Username and password required'}), 400
    
    if username not in USERS_DB:
        app.logger.warning(
            f"Login failed - User not found - "
            f"Username: {username}, "
            f"Request ID: {g.request_id}"
        )
        return jsonify({'error': 'Invalid credentials'}), 401
    
    password_hash = hashlib.sha256(password.encode()).hexdigest()
    
    if password_hash != USERS_DB[username]['password_hash']:
        app.logger.warning(
            f"Login failed - Invalid password - "
            f"Username: {username}, "
            f"Request ID: {g.request_id}"
        )
        return jsonify({'error': 'Invalid credentials'}), 401
    
    token = secrets.token_urlsafe(32)
    SESSIONS[token] = {
        'username': username,
        'role': USERS_DB[username]['role'],
        'created_at': datetime.utcnow().isoformat()
    }
    
    app.logger.info(
        f"Login successful - Username: {username}, "
        f"Role: {USERS_DB[username]['role']}, "
        f"Request ID: {g.request_id}"
    )
    
    return jsonify({
        'message': 'Login successful',
        'token': token,
        'user': {
            'username': username,
            'role': USERS_DB[username]['role']
        }
    }), 200


